const webhook = $('Webhook').first().json;
const sessionId = webhook.body.sessionId;
const data = $input.first().json;
const u = data.usuario || {};
const objetivos = data.objetivos || [];
const depositos = data.depositos || [];
const saques = data.saques || [];
const rendimentos = data.rendimentos_mensais || [];

function brl(v) {
  const parts = parseFloat(v || 0).toFixed(2).split('.');
  parts[0] = parts[0].replace(/\B(?=(\d{3})+(?!\d))/g, '.');
  return 'R$ ' + parts[0] + ',' + parts[1];
}

function fmtDate(d) {
  try { return new Date(d).toLocaleDateString('pt-BR'); } catch(e) { return String(d); }
}

let objLines = '';
if (objetivos.length === 0) {
  objLines = 'Nenhum objetivo criado ainda.';
} else {
  objLines = objetivos.map(function(obj) {
    const metas = obj.metas || [];
    const metasConcluidas = metas.filter(function(m) { return m.objetivo_completo; }).length;
    const proximaMeta = metas.find(function(m) { return !m.objetivo_completo; });
    let t = '- ' + obj.objetivo_descricao + ' | ' + metasConcluidas + '/' + metas.length + ' metas concluГӯdas';
    if (!obj.primeiro_aporte_feito) {
      t += ' | Aguardando primeiro aporte';
    } else if (proximaMeta) {
      t += ' | PrГіxima meta: ' + brl(proximaMeta.objetivo_investir) + ' atГ© ' + fmtDate(proximaMeta.data_limite) + ' (investido: ' + brl(proximaMeta.saldo_alocado) + ')';
    } else {
      t += ' | Todas as metas concluГӯdas!';
    }
    return t;
  }).join('\n');
}

const ultimosDepositos = depositos.map(function(d) {
  return '- ' + fmtDate(d.data_criacao) + ': ' + brl(d.valor_deposito) + ' (' + d.status_deposito + ')';
}).join('\n') || 'Nenhum depГіsito recente.';

const ultimosSaques = saques.map(function(s) {
  return '- ' + fmtDate(s.data_criacao) + ': ' + brl(s.valor_saque) + ' (' + s.status_saque + ')';
}).join('\n') || 'Nenhum saque recente.';


const mesesPT = ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'];
const rendimentosStr = rendimentos.length > 0
  ? rendimentos.map(function(r) {
      const parts = r.mes.split('-');
      const mesNome = mesesPT[parseInt(parts[1], 10) - 1];
      return '- ' + mesNome + '/' + parts[0] + ': ' + brl(r.rendimento_mensal);
    }).join('\n')
  : 'Nenhum rendimento registrado ainda.';
const totalRendimento = rendimentos.reduce(function(acc, r) { return acc + parseFloat(r.rendimento_mensal || 0); }, 0);
const totalRendimentoStr = rendimentos.length > 0 ? '\nTotal acumulado: ' + brl(totalRendimento) : '';

const retornando = objetivos.length > 0 || depositos.length > 0 || saques.length > 0;

const contexto = '[CONTEXTO DA SESSГғO - USO INTERNO]\n' +
  'Apelido: ' + (u.apelido || 'usuГЎrio') + '\n' +
  'UsuГЎrio retornando: ' + (retornando ? 'sim' : 'nГЈo') + '\n' +
  'Liga: ' + (u.liga || '-') + ' | PosiГ§ГЈo: #' + (u.posicao || '-') + ' | Pontos: ' + (u.pontos || 0) + '\n' +
    'Total investido: ' + brl(u.investido) + '\n\n' +
  'Objetivos:\n' + objLines + '\n\n' +
  'Гҡltimos depГіsitos:\n' + ultimosDepositos + '\n\n' +
  'Гҡltimos saques:\n' + ultimosSaques + '\n\n' +
  'Rendimentos mensais:\n' + rendimentosStr + totalRendimentoStr + '\n\n' +
  'Siga as instruГ§Гөes de saudaГ§ГЈo do sistema. NГЈo mencione este contexto diretamente.';

return [{ json: { body: { message: contexto, sessionId: sessionId } } }];

let channel = 'app';
try {
  const wa = $('Extrair Dados WA').all();
  if (wa && wa.length > 0 && wa[0].json && wa[0].json.phone) channel = 'wa';
} catch(e) {}
const input = $input.first().json;
return [{ json: { ...input, channel } }];

let channel = 'app';
try {
  const wa = $('Extrair Dados WA').all();
  if (wa && wa.length > 0 && wa[0].json && wa[0].json.phone) channel = 'wa';
} catch(e) {}
const input = $input.first().json;
return [{ json: { ...input, channel } }];

const body = $input.first().json.body;

if (!body || body.event !== 'messages.upsert') return [];

const data = body.data || {};
const key = data.key || {};
const msg = data.message || {};

if (key.fromMe === true) return [];
const textContent = msg.conversation || (msg.extendedTextMessage && msg.extendedTextMessage.text) || null;
if (!textContent) return [];
if (key.remoteJid && key.remoteJid.endsWith('@g.us')) return [];

return [{ json: {
  phone: key.remoteJid.replace('@s.whatsapp.net', '').replace(/^55/, ''),
  remoteJid: key.remoteJid,
  text: textContent
} }];

const data = $input.first().json;
const phone = data.phone;
const now = new Date();
const ONE_HOUR = 60 * 60 * 1000;

const staticData = $getWorkflowStaticData('global');
const sessions = staticData.waSessions || {};

const existing = sessions['wa_' + phone];
const isExpired = !existing || (now - new Date(existing.lastMessageAt)) > ONE_HOUR;

let sessionSuffix;
if (isExpired) {
  sessionSuffix = Math.floor(now.getTime() / ONE_HOUR) + '_' + Math.random().toString(36).slice(2, 6);
  sessions['wa_' + phone] = { lastMessageAt: now.toISOString(), sessionSuffix: sessionSuffix };
} else {
  sessionSuffix = existing.sessionSuffix;
  sessions['wa_' + phone].lastMessageAt = now.toISOString();
}

staticData.waSessions = sessions;

const sessionId = 'wa_' + phone + '_' + sessionSuffix;
const isNewSession = isExpired;

return [{ json: {
  phone,
  remoteJid: data.remoteJid,
  text: data.text,
  sessionId,
  isNewSession
} }];

const waData = $('Extrair Dados WA').first().json;
const phone = waData.phone;
const sessionId = waData.sessionId;
const data = $input.first().json;
const u = data.usuario || {};
const objetivos = data.objetivos || [];
const depositos = data.depositos || [];
const saques = data.saques || [];
const rendimentos = data.rendimentos_mensais || [];

function brl(v) {
  const parts = parseFloat(v || 0).toFixed(2).split('.');
  parts[0] = parts[0].replace(/\B(?=(\d{3})+(?!\d))/g, '.');
  return 'R$ ' + parts[0] + ',' + parts[1];
}
function fmtDate(d) {
  try { return new Date(d).toLocaleDateString('pt-BR'); } catch(e) { return String(d); }
}

let objLines = '';
if (objetivos.length === 0) {
  objLines = 'Nenhum objetivo criado ainda.';
} else {
  objLines = objetivos.map(function(obj) {
    const metas = obj.metas || [];
    const totalMetas = metas.length;
    const valorAporte = metas.length > 0 ? parseFloat(metas[0].objetivo_investir || 0) : 0;
    const metasMensais = metas.slice(1);
    const metasMensaisConcluidas = metasMensais.filter(function(m) { return m.objetivo_completo; }).length;
    const metasMensaisPendentes = metasMensais.length - metasMensaisConcluidas;
    const valorTotal = metas.reduce(function(acc, m) { return acc + parseFloat(m.objetivo_investir || 0); }, 0);
    const totalInvestido = metas.reduce(function(acc, m) { return acc + parseFloat(m.saldo_alocado || 0); }, 0);
    const percentual = valorTotal > 0 ? (totalInvestido / valorTotal * 100).toFixed(1) : '0.0';
    const proximaMeta = metas.find(function(m) { return !m.objetivo_completo; });
    let t = '- ' + obj.objetivo_descricao;
    t += ' | Valor total: ' + brl(valorTotal);
    t += ' | Investido: ' + brl(totalInvestido) + ' (' + percentual + '%)';
    t += ' | Aporte inicial: ' + brl(valorAporte) + (obj.primeiro_aporte_feito ? ' (feito)' : ' (pendente)');
    t += ' | Metas mensais: ' + metasMensais.length + ' total, ' + metasMensaisConcluidas + ' concluidas, ' + metasMensaisPendentes + ' pendentes';
    if (proximaMeta) {
      t += ' | Proxima meta: ' + brl(proximaMeta.objetivo_investir) + ' ate ' + fmtDate(proximaMeta.data_limite) + ' (investido: ' + brl(proximaMeta.saldo_alocado) + ')';
    } else {
      t += ' | Todas as metas concluidas!';
    }
    return t;
  }).join('\n');
}
const ultimosDepositos = depositos.map(function(d) {
  return '- ' + fmtDate(d.data_criacao) + ': ' + brl(d.valor_deposito) + ' (' + d.status_deposito + ')';
}).join('\n') || 'Nenhum depГіsito recente.';

const ultimosSaques = saques.map(function(s) {
  return '- ' + fmtDate(s.data_criacao) + ': ' + brl(s.valor_saque) + ' (' + s.status_saque + ')';
}).join('\n') || 'Nenhum saque recente.';

const mesesPT = ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'];
const rendimentosStr = rendimentos.length > 0
  ? rendimentos.map(function(r) {
      const parts = r.mes.split('-');
      const mesNome = mesesPT[parseInt(parts[1], 10) - 1];
      return '- ' + mesNome + '/' + parts[0] + ': ' + brl(r.rendimento_mensal);
    }).join('\n')
  : 'Nenhum rendimento registrado ainda.';
const totalRendimento = rendimentos.reduce(function(acc, r) { return acc + parseFloat(r.rendimento_mensal || 0); }, 0);
const totalRendimentoStr = rendimentos.length > 0 ? '\nTotal acumulado: ' + brl(totalRendimento) : '';

const apelido = u.apelido || 'usuГЎrio';
const contexto = 'Apelido: ' + apelido + '\n' +
  'Liga: ' + (u.liga || '-') + ' | PosiГ§ГЈo: #' + (u.posicao || '-') + ' | Pontos: ' + (u.pontos || 0) + '\n' +
  'Total investido: ' + brl(u.investido) + '\n\n' +
  'Objetivos:\n' + objLines + '\n\n' +
  'Гҡltimos depГіsitos:\n' + ultimosDepositos + '\n\n' +
  'Гҡltimos saques:\n' + ultimosSaques + '\n\n' +
  'Rendimentos mensais:\n' + rendimentosStr + totalRendimentoStr;

const staticData = $getWorkflowStaticData('global');
const sessions = staticData.waSessions || {};
if (sessions['wa_' + phone]) {
  sessions['wa_' + phone].contexto = contexto;
  sessions['wa_' + phone].apelido = apelido;
  sessions['wa_' + phone].tokens = $input.first().json.tokens || [];
}

// Salvar status de objetivo na sessГЈo e forГ§ar criaГ§ГЈo se necessГЎrio
const temObjetivo = objetivos.length > 0;
if (sessions['wa_' + phone]) {
  sessions['wa_' + phone].temObjetivo = temObjetivo;
  if (!temObjetivo && !sessions['wa_' + phone].depositStep) {
    sessions['wa_' + phone].depositStep = 'sem_objetivo_confirm';
  }
}
staticData.waSessions = sessions;

const retornando = objetivos.length > 0 || depositos.length > 0;
let saudacao;
if (!temObjetivo) {
  saudacao = 'Oi ' + apelido + '! рҹ‘Ӣ\n\nPara comeГ§ar a usar a Purg, vocГӘ precisa criar o seu *_objetivo_* primeiro. рҹҺҜ\n\nГү rapidinho! Vamos criar juntos?\n\nResponda *_sim_* para comeГ§ar.';
} else {
  saudacao = retornando
    ? 'Oi ' + apelido + ', que bom que voltou!\n\nJГЎ sabe sobre o que quer falar?\n\nSe nГЈo souber, me manda *_dicas_* que eu te ajudo!'
    : 'Oi ' + apelido + '! Sou a Purg, bem-vindo!\n\nJГЎ sabe sobre o que quer falar?\n\nSe nГЈo souber, me manda *_dicas_* que eu te ajudo!';
}

// Salvar usuarioId e valor da prГіxima meta para fluxo de depГіsito
try {
  const uid = $('Buscar UsuГЎrio por Celular').first().json.usuario_id;
  if (sessions['wa_' + phone] && uid) {
    sessions['wa_' + phone].usuarioId = uid;
    if (objetivos.length > 0) {
      const obj = objetivos[0];
      const pendentes = (obj.metas || []).filter(function(m) { return !m.objetivo_completo; });
      if (pendentes.length > 0 && obj.primeiro_aporte_feito) {
        const pm = pendentes[0];
        const resto = parseFloat(pm.objetivo_investir) - parseFloat(pm.saldo_alocado);
        if (resto > 0) sessions['wa_' + phone].proximaMetaValor = resto.toFixed(2);
      }
    }
    staticData.waSessions = sessions;
  }
} catch(e) {}

return [{ json: { output: saudacao, sessionId } }];

const waData = $('Extrair Dados WA').first().json;
const phone = waData.phone;
const sessionId = waData.sessionId;
const text = waData.text;

const staticData = $getWorkflowStaticData('global');
const sessions = staticData.waSessions || {};
const session = sessions['wa_' + phone];

// Salvar usuarioId para o fluxo de depГіsito
try {
  const uid = $('Buscar UsuГЎrio por Celular').first().json.usuario_id;
  if (session && uid) { session.usuarioId = uid; staticData.waSessions = sessions; }
} catch(e) {}

const contexto = session && session.contexto ? session.contexto : '';
const message = contexto
  ? '[Dados do usuario:\n' + contexto + ']\n\n' + text
  : text;

return [{ json: { body: { message, sessionId } } }];

const item = $input.first().json;
let text = (item.output || '').trim();

// Separar frases em parГЎgrafos
text = text.replace(/([.!?])\s+([A-ZГҖ-Гң])/g, '$1\n\n$2');

// Garantir que termina com pergunta
if (!text.trim().endsWith('?')) {
  const lower = text.toLowerCase();
  const isHistorico = (text.match(/^- /gm) || []).length >= 2;
  const hasDepositAmount = /depositar r\$\s*[\d.,]+/i.test(text) || /precisa depositar/i.test(text);
  let pergunta;
  if (hasDepositAmount) {
    pergunta = 'J\u00e1 quer fazer o dep\u00f3sito?';
  } else if (isHistorico) {
    if (lower.includes('dep\u00f3sito') || lower.includes('deposito')) {
      pergunta = 'Quer ver o hist\u00f3rico de saques?';
    } else if (lower.includes('saque')) {
      pergunta = 'Quer ver o hist\u00f3rico de dep\u00f3sitos?';
    } else if (lower.includes('meta') || lower.includes('objetivo')) {
      pergunta = 'Quer ver seus \u00faltimos dep\u00f3sitos?';
    } else {
      pergunta = 'Posso te ajudar com mais alguma coisa sobre a sua conta?';
    }
  } else {
    if (lower.includes('meta') || lower.includes('objetivo')) {
      pergunta = 'Quer ver o progresso das outras metas?';
    } else if (lower.includes('dep\u00f3sito') || lower.includes('deposito')) {
      pergunta = 'Quer ver o hist\u00f3rico de dep\u00f3sitos?';
    } else if (lower.includes('saque')) {
      pergunta = 'Quer ver o hist\u00f3rico de saques?';
    } else if (lower.includes('rank') || lower.includes('liga') || lower.includes('ponto')) {
      pergunta = 'Quer ver seu total investido?';
    } else if (lower.includes('invest') || lower.includes('patrim')) {
      pergunta = 'Quer ver o progresso das suas metas?';
    } else {
      pergunta = 'Posso te ajudar com mais alguma coisa sobre a sua conta?';
    }
  }
  text = text.trim() + '\n\n' + pergunta;
}

// Detectar se a resposta final pede depГіsito вҶ’ ativar fluxo
if (/j\u00e1 quer fazer o dep\u00f3sito\?/i.test(text) || /quer fazer o dep\u00f3sito\?/i.test(text)) {
  try {
    const waPhone = $('Extrair Dados WA').first().json.phone;
    const sd = $getWorkflowStaticData('global');
    const sess = sd.waSessions || {};
    if (sess['wa_' + waPhone]) {
      sess['wa_' + waPhone].depositStep = 'confirm_amount';
      // Tentar extrair valor do texto
      const valM = text.match(/depositar R\$\s*([\d.,]+)/i);
      if (valM) {
        sess['wa_' + waPhone].depositValue = valM[1].replace(/\./g,'').replace(',','.');
      } else if (sess['wa_' + waPhone].proximaMetaValor) {
        sess['wa_' + waPhone].depositValue = sess['wa_' + waPhone].proximaMetaValor;
      }
      sd.waSessions = sess;
    }
  } catch(e) {}
}

return [{ json: { output: text } }];

const waData = $('Extrair Dados WA').first().json;
const phone = waData.phone;
const text = waData.text.trim();
const prepBody = $('Preparar Mensagem WA').first().json.body;
const staticData = $getWorkflowStaticData('global');
const sessions = staticData.waSessions || {};
const session = sessions['wa_' + phone] || {};
let depositStep = session.depositStep || null;

// Se o usuГЎrio nГЈo tem objetivo, forГ§ar criaГ§ГЈo independente do que ele digitar
const objSteps = ['sem_objetivo_confirm', 'obj_valor', 'obj_prazo', 'obj_aporte', 'obj_confirm', 'obj_alterar'];
if (session.temObjetivo === false && (!depositStep || !objSteps.includes(depositStep))) {
  sessions['wa_' + phone].depositStep = 'sem_objetivo_confirm';
  staticData.waSessions = sessions;
  return [{ json: {
    isDeposito: true, body: prepBody, depositStep: 'sem_objetivo_confirm',
    usuarioId: session.usuarioId || null,
    phone, text, sessionId: waData.sessionId
  } }];
}

if (!depositStep) return [{ json: { isDeposito: false, body: prepBody } }];
return [{ json: {
  isDeposito: true, body: prepBody, depositStep,
  depositValue: session.depositValue || null,
  metasVencidas: session.metasVencidas || null,
  objData: session.objData || null,
  parcelaValor: session.parcelaValor || null,
  usuarioId: session.usuarioId || null,
  phone, text, sessionId: waData.sessionId
} }];

const info = $input.first().json;
const { depositStep, depositValue, metasVencidas, objData, parcelaValor, phone, usuarioId, text, sessionId } = info;
const staticData = $getWorkflowStaticData('global');
const sessions = staticData.waSessions || {};

function brl(v) {
  const p = parseFloat(v || 0).toFixed(2).split('.');
  p[0] = p[0].replace(/\B(?=(\d{3})+(?!\d))/g, '.');
  return 'R$ ' + p[0] + ',' + p[1];
}

const norm = text.trim().toLowerCase();
const isSim     = /^(1|sim|yes|quero|pode|claro|ok|confirmar?|fa[cГ§]a?)(\s|$)/i.test(norm);
const isNao     = /^(2|outro|outra|diferente|muda|n[aГЈ]o|nao)/.test(norm);
const isCancel  = /^(3|cancel|cancelar|sair|parar|desistir|n[aГЈ]o|nao)/.test(norm);
const isConfirm = /^(confirmar?|sim|yes|quero|pode|claro|ok|1|fa[cГ§]a?)(\s|$)/i.test(norm);
const isAlterar = /^(alterar?|mudar?|2|trocar?)(\s|$)/i.test(norm);

function parseValorInput(t) {
  const c = t.replace(/r\$\s*/i,'').replace(/\./g,'').replace(',','.').trim();
  const m = c.match(/^(\d+(?:\.\d{1,2})?)$/);
  if (!m) return null;
  const v = parseFloat(m[1]);
  return v > 0 ? v : null;
}

function parsePrazoInput(t) {
  const m = t.trim().match(/^(\d{2})\/(\d{2})\/(\d{4})$/);
  if (!m) return null;
  const day = parseInt(m[1]), month = parseInt(m[2]) - 1, year = parseInt(m[3]);
  if (month < 0 || month > 11 || day < 1 || day > 31 || year < 2020) return null;
  const target   = new Date(year, month, 1);
  const nowStart = new Date(new Date().getFullYear(), new Date().getMonth(), 1);
  const diff = (target.getFullYear() - nowStart.getFullYear()) * 12 + (target.getMonth() - nowStart.getMonth());
  if (diff < 1 || diff > 600) return null;
  const lastDay = new Date(year, month + 1, 0).toLocaleDateString('pt-BR');
  return { prazo: diff, display: lastDay };
}

let output = '', callPix = false, pixValue = null, callCriarObjetivo = false;
const confirmMsg = 'Quer fazer o depГіsito de ' + brl(depositValue) + '?\n\nDigite:\n\n*_1_* - para confirmar\n*_2_* - para escolher outro valor\n*_3_* - para cancelar';

if (depositStep === 'confirm_amount') {
  if (isSim) {
    callPix = true; pixValue = depositValue;
    delete sessions['wa_' + phone].depositStep; delete sessions['wa_' + phone].depositValue;
  } else if (isCancel) {
    delete sessions['wa_' + phone].depositStep; delete sessions['wa_' + phone].depositValue;
    output = 'Tudo bem, cancelei o depГіsito.\n\nComo mais posso te ajudar?\n\n- Seus *_objetivos_*\n- Suas *_metas_*\n- Seus *_depГіsitos_*\n- Seus *_saques_*\n- Sua posiГ§ГЈo no *_ranking_*\n- Sua *_pontuaГ§ГЈo_*\n- Quanto vocГӘ jГЎ tem *_investido_*\n- Qual o seu *_rendimento_*\n- Fazer um depГіsito *_Pix_*\n\nQual desses vocГӘ quer saber?';
  } else if (isNao) {
    sessions['wa_' + phone].depositStep = 'ask_custom';
    output = 'Tudo bem!\n\nQual valor vocГӘ quer depositar?';
  } else { output = confirmMsg; }

} else if (depositStep === 'ask_custom') {
  if (isCancel) {
    delete sessions['wa_' + phone].depositStep; delete sessions['wa_' + phone].depositValue;
    output = 'Tudo bem, cancelei o depГіsito.\n\nComo mais posso te ajudar?\n\n- Seus *_objetivos_*\n- Suas *_metas_*\n- Seus *_depГіsitos_*\n- Seus *_saques_*\n- Sua posiГ§ГЈo no *_ranking_*\n- Sua *_pontuaГ§ГЈo_*\n- Quanto vocГӘ jГЎ tem *_investido_*\n- Qual o seu *_rendimento_*\n- Fazer um depГіsito *_Pix_*\n\nQual desses vocГӘ quer saber?';
  } else {
    const c2 = text.replace(/r\$\s*/i,'').replace(/\./g,'').replace(',','.');
    const m2 = c2.match(/(\d+(?:\.\d{1,2})?)/);
    if (m2 && parseFloat(m2[1]) >= 1) {
      pixValue = parseFloat(m2[1]).toFixed(2); callPix = true;
      delete sessions['wa_' + phone].depositStep; delete sessions['wa_' + phone].depositValue;
    } else { output = 'NГЈo entendi o valor.\n\nMe diz quanto quer depositar. Exemplo: 50,00\n\nOu digite *_3_* para cancelar.'; }
  }

} else if (depositStep === 'meta_vencida_confirm') {
  const metas = metasVencidas || [];
  if (isSim) {
    if (metas.length === 1) {
      pixValue = (parseFloat(metas[0].valor_meta) - parseFloat(metas[0].valor_alocado)).toFixed(2);
