      output = 'VocГӘ tem ' + metas.length + ' metas atrasadas:\n\n' + linhas.join('\n') + '\n\nQuantas quer acertar agora? (1 a ' + metas.length + ')\n\nOu *_cancelar_* para sair.';
    }
