    delete sessions['wa_' + phone].depositStep; delete sessions['wa_' + phone].metasVencidas;
    output = 'Tudo bem! Se quiser criar o Pix depois, Г© sГі me chamar.';
  } else { output = 'Quer que eu crie o Pix para regularizar as metas?\n\nResponda *_sim_* para confirmar ou *_nГЈo_* para cancelar.'; }

} else if (depositStep === 'meta_vencida_count') {
  const metas = metasVencidas || [];
  if (isCancel) {
    delete sessions['wa_' + phone].depositStep; delete sessions['wa_' + phone].metasVencidas;
    output = 'Tudo bem! Se quiser criar o Pix depois, Г© sГі me chamar.';
  } else {
    const qty = parseInt(norm, 10);
    if (!isNaN(qty) && qty >= 1 && qty <= metas.length) {
