} else if (depositStep === 'obj_aporte') {
  const obj = sessions['wa_' + phone].objData || {};
  let aporte = 0;
  const isZero = /^(0|n[aГЈ]o|nao|nГЈo|nope|sem)(\s|$)/i.test(norm);
  if (isZero) {
    aporte = 0;
