function brl(v) {
  const parts = parseFloat(v || 0).toFixed(2).split('.');
  parts[0] = parts[0].replace(/\B(?=(\d{3})+(?!\d))/g, '.');
  return 'R$ ' + parts[0] + ',' + parts[1];
}

function num8(v) {
  const n = v * 1;
  const str = n.toFixed(8);
  const dot = str.indexOf('.');
  const intPart = str.slice(0, dot);
  const decPart = str.slice(dot + 1);
  return intPart.replace(/\B(?=(\d{3})+(?!\d))/g, '.') + ',' + decPart;
}

function fmtDate(d) {
  try { return new Date(d).toLocaleDateString('pt-BR'); } catch(e) { return String(d); }
}

function fmtQty(n) {
