const totalInvestido = tokens.reduce(function(acc, t) { return acc + (t.valor_token * t.quantidade_tokens); }, 0);
const rendDiarioTotal = tokens.reduce(function(acc, t) { return acc + t.rendimento_token; }, 0);
const numPins = tokens.length;

// Agrupar por risco
const byRisk = {};
for (const t of tokens) {
  const r = t.risco || 'N/A';
  if (!byRisk[r]) byRisk[r] = { pins: 0, investido: 0, rendDiario: 0 };
  byRisk[r].pins++;
  byRisk[r].investido += t.valor_token * t.quantidade_tokens;
  byRisk[r].rendDiario += t.rendimento_token;
}

