}

const totalInvestido = tokens.reduce(function(acc, t) { return acc + (t.valor_token * t.quantidade_tokens); }, 0);
const rendDiarioTotal = tokens.reduce(function(acc, t) { return acc + t.rendimento_token; }, 0);
const numPins = tokens.length;

// Agrupar por risco
const byRisk = {};
for (const t of tokens) {
  const r = t.risco || 'N/A';
  if (!byRisk[r]) byRisk[r] = { pins: 0, investido: 0, rendDiario: 0 };
  byRisk[r].pins++;
  byRisk[r].investido += t.valor_token * t.quantidade_tokens;
  byRisk[r].rendDiario += t.rendimento_token;
}

let msg = '*_рҹ“Ң Seus Pins_*\n\n';
msg += 'OlГЎ, ' + apelido + '! Aqui estГЎ um resumo dos seus Pins:\n\n';

msg += '*_рҹ“Ӣ VisГЈo Geral_*\n\n';
msg += 'рҹ’° Total investido em Pins: ' + brl(totalInvestido) + '\n';
msg += 'рҹҺҜ Pins diferentes: ' + numPins + '\n';
msg += 'рҹ“Ҳ Rendimento diГЎrio total: R$ ' + num8(rendDiarioTotal) + '\n\n';

msg += '*_рҹ”җ Por NГӯvel de Risco_*\n\n';
for (const [risco, data] of Object.entries(byRisk)) {
  msg += 'рҹ’° *_Risco ' + risco + '_*\n';
  msg += 'Pins: ' + data.pins + '\n';
  msg += 'Investido: ' + brl(data.investido) + '\n';
  msg += 'Rendimento diГЎrio: R$ ' + num8(data.rendDiario) + '\n\n';
}

msg += '*_рҹ“Ң Detalhe dos Pins_*\n\n';
for (const t of tokens) {
  const invest = t.valor_token * t.quantidade_tokens;
  const rend = t.rendimento_token;
  msg += 'рҹ“Ң *_' + (t.razao_social || 'Pin ' + t.token_id) + '_*\n';
  msg += 'Risco: ' + (t.risco || 'N/A') + '\n';
  msg += 'Quantidade: ' + fmtQty(t.quantidade_tokens) + ' tokens\n';
  msg += 'Valor por token: ' + brl(t.valor_token) + '\n';
  msg += 'Total investido: ' + brl(invest) + '\n';
  msg += 'Rendimento diГЎrio: R$ ' + num8(rend) + '\n';
  msg += 'Vencimento: ' + fmtDate(t.vencimento) + '\n\n';
}

msg += 'Quer saber mais sobre o seu Objetivo? Me manda *_objetivo_*';

return [{ json: { output: msg } }];
